create table dirkspzm32.pzm_personal (
    pers_nr                    number(*, 0) not null enable,
    pers_anrede                varchar2(20 char),
    pers_nname                 varchar2(255 char) not null enable,
    pers_vname                 varchar2(255 char) not null enable,
    pers_land                  varchar2(255 char),
    pers_region_code           varchar2(255 char),
    pers_pb_id                 number(*, 0),
    pers_abt_id                number(*, 0),
    pers_kst_id                number(*, 0),
    pers_taetigkeit            varchar2(100 char),
    pers_vertragsart           number(*, 0),
    pers_eintrittsdatum        date,
    pers_austrittdatum         date,
    pers_sm_name               varchar2(100 char),
    pers_sm_beginn             date,
    pers_befristet_bis         date,
    pers_ustd_freistd          varchar2(10 char) default 'AZ',
    pers_max_freistd           number(*, 0) default 20,
    pers_zk_von1_freistd       number(*, 5),
    pers_zk_bis1_freistd       number(*, 5),
    pers_zk_von2_freistd       number(*, 5),
    pers_zk_bis2_freistd       number(*, 5),
    pers_kennz_zeiterf         number(*, 0) default 1 not null enable,
    pers_schnittstelle         number(*, 0),
    pers_personalteilber       varchar2(15 char),
    pers_kappung_me_ab_flx_std number(*, 5),
    pers_kappung_te_ab_flx_std number(*, 5),
    pers_kappung_schicht_ende  varchar2(1 char) default 'F' not null enable,
    pers_urlaub_anspr_wert     number(*, 3),
    pers_urlaub_anspr_aa_id    number(*, 0),
    pers_sm_beginn_woche       number(*, 5),
    pers_verfall_vorjahr       date default to_date('31.03.' || to_char(sysdate, 'yyyy'),
        'dd.mm.yyyy') not null enable,
    pers_startdatum            date,
    tarif_name                 varchar2(50 char),
    created_date               date default sysdate not null enable,
    created_login_id           number(*, 0) default - 1 not null enable,
    last_change_date           date,
    last_change_login_id       number(*, 0)
);

alter table dirkspzm32.pzm_personal
    add constraint pk_pers_nr primary key ( pers_nr )
        using index enable;


